import{c as e,Q as r,j as t,m as l}from"./chunks/framework.BXc4yaFE.js";const u=JSON.parse('{"title":"Andrej Karpathy Skills - Claude Code Guidelines (GitHub Repository)","description":"","frontmatter":{"url":"https://github.com/forrestchang/andrej-karpathy-skills","title":"Andrej Karpathy Skills - Claude Code Guidelines (GitHub Repository)","author":"Forrest Chang","date":2026,"status":"SUCCESS"},"headers":[],"relativePath":"research/ai-articles/09-forrestchang-andrej-karpathy-skills-readme.md","filePath":"research/ai-articles/09-forrestchang-andrej-karpathy-skills-readme.md","lastUpdated":1779894392000}'),o={name:"research/ai-articles/09-forrestchang-andrej-karpathy-skills-readme.md"};function i(s,a,n,d,h,p){return r(),t("div",null,[...a[0]||(a[0]=[l('<h1 id="andrej-karpathy-skills-claude-code-guidelines" tabindex="-1">Andrej Karpathy Skills: Claude Code Guidelines <a class="header-anchor" href="#andrej-karpathy-skills-claude-code-guidelines" aria-label="Permalink to &quot;Andrej Karpathy Skills: Claude Code Guidelines&quot;">​</a></h1><h2 id="項目概述" tabindex="-1">項目概述 <a class="header-anchor" href="#項目概述" aria-label="Permalink to &quot;項目概述&quot;">​</a></h2><p><strong>名稱</strong>：Karpathy-Inspired Claude Code Guidelines<br><strong>作者</strong>：Forrest Chang（開源社區貢獻者）<br><strong>倉庫</strong>：forrestchang/andrej-karpathy-skills<br><strong>數據</strong>：135,000+ 顆星，13,800+ forks</p><h2 id="項目目標" tabindex="-1">項目目標 <a class="header-anchor" href="#項目目標" aria-label="Permalink to &quot;項目目標&quot;">​</a></h2><p>這是一個單一 <code>CLAUDE.md</code> 配置檔案，設計用來改善 Claude Code 的編碼行為。該檔案基於 AI 研究者 Andrej Karpathy 對 LLM 編碼常見錯誤的觀察。</p><h2 id="四項核心原則" tabindex="-1">四項核心原則 <a class="header-anchor" href="#四項核心原則" aria-label="Permalink to &quot;四項核心原則&quot;">​</a></h2><p><strong>1. 編碼前思考（Think Before Coding）</strong></p><p>避免隱藏假設；在實施前明確呈現困惑和權衡。當面對模糊需求時，提出多個解釋選項，讓人類開發者確認正確方向，而非自信地猜測。</p><p><strong>2. 簡潔優先（Simplicity First）</strong></p><p>編寫僅解決陳述問題的最小代碼。拒絕過度工程化、不必要的抽象層和投機性功能。遵循「做最簡單能工作的事」的原則。</p><p><strong>3. 精準修改（Surgical Changes）</strong></p><p>僅修改必要部分；保留既有代碼風格和約定。避免改進不相關的代碼段或進行不相關的重構。每一行改動都應能直接追溯至用戶請求。</p><p><strong>4. 目標驅動執行（Goal-Driven Execution）</strong></p><p>將任務轉化為可驗證的成功標準。例如，不說「修復這個 bug」，改為「寫一個複現 bug 的測試，然後讓測試通過」。這使 LLM 能獨立地迭代直至目標達成。</p><h2 id="解決的關鍵問題" tabindex="-1">解決的關鍵問題 <a class="header-anchor" href="#解決的關鍵問題" aria-label="Permalink to &quot;解決的關鍵問題&quot;">​</a></h2><p>該指南針對三個主要問題：</p><ol><li><strong>無根據的假設配合無聲接受</strong>：AI 做出假設後盲目執行，不尋求澄清</li><li><strong>過度複雜的解決方案</strong>：AI 傾向於添加不必要的功能和冗長的抽象層</li><li><strong>無意中的代碼修改</strong>：修改無關代碼段，引入難以追蹤的副效應</li></ol><h2 id="安裝方法" tabindex="-1">安裝方法 <a class="header-anchor" href="#安裝方法" aria-label="Permalink to &quot;安裝方法&quot;">​</a></h2><p><strong>方法一：Claude Code 外掛</strong></p><p>通過市場安裝：<code>forrestchang/andrej-karpathy-skills</code>（全局配置，一次性設置）</p><p><strong>方法二：按項目配置</strong></p><p>直接將 CLAUDE.md 檔案複製到你的項目根目錄。這允許根據特定項目的需求進行定製。</p><h2 id="核心洞察" tabindex="-1">核心洞察 <a class="header-anchor" href="#核心洞察" aria-label="Permalink to &quot;核心洞察&quot;">​</a></h2><p>根據 Karpathy 的觀點：<strong>將含糊的命令式指示轉化為聲明式目標，使 LLM 能有效地循環達成完成條件</strong>。</p><p>這一轉變改變了人類與 AI 的互動模式，從簡單的「做這件事」到「達成這個明確的、可驗證的結果」。</p><h2 id="實踐價值" tabindex="-1">實踐價值 <a class="header-anchor" href="#實踐價值" aria-label="Permalink to &quot;實踐價值&quot;">​</a></h2><ul><li><strong>零依賴</strong>：無需新工具或複雜配置</li><li><strong>立即生效</strong>：文本檔案，無須安裝或編譯</li><li><strong>高效可組合</strong>：可與其他專案實踐層層堆疊</li><li><strong>持久記憶</strong>：CLAUDE.md 在每個會話自動加載，提供一致的指導</li></ul><h2 id="社區反應" tabindex="-1">社區反應 <a class="header-anchor" href="#社區反應" aria-label="Permalink to &quot;社區反應&quot;">​</a></h2><p>該項目在 GitHub 社區中引起了廣泛共鳴，許多開發者報告了使用這些指南後的顯著改進：</p><ul><li>代碼審查時間大幅減少</li><li>無關修改幾乎消失</li><li>AI 與人類開發者的協作效率提升</li><li>整體代碼品質和可維護性改善</li></ul><h2 id="擴展與變體" tabindex="-1">擴展與變體 <a class="header-anchor" href="#擴展與變體" aria-label="Permalink to &quot;擴展與變體&quot;">​</a></h2><p>該概念已衍生出針對其他 AI 工具的變體，如 GEMINI.md（用於 Gemini）和 AGENTS.md（用於代理系統），展示了這一方法論的通用適用性。</p><h2 id="許可證" tabindex="-1">許可證 <a class="header-anchor" href="#許可證" aria-label="Permalink to &quot;許可證&quot;">​</a></h2><p>MIT License（開源，允許自由使用和修改）</p>',34)])])}const g=e(o,[["render",i]]);export{u as __pageData,g as default};
